def process_user_data(users):
    result = []
    for i in range(len(users)):
        user = users[i]
        if user['age'] > 18:
            if user['status'] == 'active':
                user['name'] = user['name'].strip().lower()
                user['email'] = user['email'].strip().lower()
                if user['email'].endswith('@gmail.com') or user['email'].endswith('@yahoo.com') or user['email'].endswith('@hotmail.com'):
                    user['email_type'] = 'personal'
                else:
                    user['email_type'] = 'work'
                user['score'] = 0
                for purchase in user['purchases']:
                    user['score'] = user['score'] + purchase['amount']
                result.append(user)
    return result
